-- 1. Ensure profiles table has required columns&#10;ALTER TABLE profiles &#10;ADD COLUMN IF NOT EXISTS is_approved boolean DEFAULT false;&#10;&#10;ALTER TABLE profiles &#10;ADD COLUMN IF NOT EXISTS status text DEFAULT 'pending' &#10;CHECK (status IN ('pending', 'active', 'inactive', 'suspended'));&#10;&#10;-- 2. Add interviewer_id column as NULL first&#10;ALTER TABLE interviews &#10;ADD COLUMN IF NOT EXISTS interviewer_id uuid REFERENCES profiles(id) ON DELETE CASCADE;&#10;&#10;-- 3. Fix existing NULL values&#10;DO $$&#10;DECLARE&#10;  default_profile_id uuid;&#10;BEGIN&#10;  SELECT id INTO default_profile_id&#10;  FROM profiles &#10;  ORDER BY created_at DESC&#10;  LIMIT 1;&#10;  &#10;  IF default_profile_id IS NOT NULL THEN&#10;    UPDATE interviews &#10;    SET interviewer_id = default_profile_id&#10;    WHERE interviewer_id IS NULL;&#10;  END IF;&#10;  &#10;  DELETE FROM interviews &#10;  WHERE interviewer_id IS NULL;&#10;END $$;&#10;&#10;-- 4. Make NOT NULL&#10;ALTER TABLE interviews &#10;ALTER COLUMN interviewer_id SET NOT NULL;&#10;&#10;-- 5. Create tables&#10;CREATE TABLE IF NOT EXISTS interview_evaluations (&#10;  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,&#10;  interview_id uuid NOT NULL REFERENCES interviews(id) ON DELETE CASCADE,&#10;  category text NOT NULL,&#10;  rating integer NOT NULL CHECK (rating >= 1 AND rating <= 5),&#10;  comments text,&#10;  created_at timestamp with time zone DEFAULT timezone('utc'::text, now()),&#10;  updated_at timestamp with time zone DEFAULT timezone('utc'::text, now())&#10;);&#10;&#10;CREATE TABLE IF NOT EXISTS final_decisions (&#10;  id uuid DEFAULT gen_random_uuid() PRIMARY KEY,&#10;  interview_id uuid NOT NULL UNIQUE REFERENCES interviews(id) ON DELETE CASCADE,&#10;  education_verified boolean DEFAULT false,&#10;  recommendation text CHECK (recommendation IN ('Advance', 'Advance with Reservations', 'Do Not Advance')),&#10;  overall_score numeric,&#10;  overall_comments text,&#10;  created_at timestamp with time zone DEFAULT timezone('utc'::text, now()),&#10;  updated_at timestamp with time zone DEFAULT timezone('utc'::text, now())&#10;);&#10;&#10;-- 6. RLS&#10;ALTER TABLE interviews ENABLE ROW LEVEL SECURITY;&#10;ALTER TABLE interview_evaluations ENABLE ROW LEVEL SECURITY;&#10;ALTER TABLE final_decisions ENABLE ROW LEVEL SECURITY;&#10;&#10;-- 7. Policies&#10;DROP POLICY IF EXISTS "Recruiters can view interviews" ON interviews;&#10;CREATE POLICY "Recruiters can view interviews" ON interviews &#10;  FOR SELECT USING (&#10;    EXISTS (&#10;      SELECT 1 FROM profiles &#10;      WHERE id = auth.uid() &#10;      AND role = 'recruiter' &#10;      AND (is_approved = true OR is_approved IS NULL)&#10;    ) OR&#10;    interviewer_id = auth.uid()&#10;  );&#10;&#10;DROP POLICY IF EXISTS "Recruiters can create interviews" ON interviews;&#10;CREATE POLICY "Recruiters can create interviews" ON interviews &#10;  FOR INSERT WITH CHECK (&#10;    EXISTS (&#10;      SELECT 1 FROM profiles &#10;      WHERE id = auth.uid() &#10;      AND role = 'recruiter' &#10;      AND (is_approved = true OR is_approved IS NULL)&#10;    )&#10;  );
